import React, { useState } from 'react';
import './ComponentModal.css';
import { X, Image, Send } from 'lucide-react';

interface ComponentModalProps {
  isOpen: boolean;
  onClose: () => void;
  onGenerate: (prompt: string) => void;
  editingComponent?: {
    id: string;
    prompt: string;
  } | null;
}

const ComponentModal: React.FC<ComponentModalProps> = ({ isOpen, onClose, onGenerate }) => {
  const [prompt, setPrompt] = useState('');
  const [designSystem, setDesignSystem] = useState('No design system');

  const examplePrompts = [
    'Sign in card',
    'File upload component', 
    'Modern SaaS landing page',
    'A music player card'
  ];

  const handleGenerate = () => {
    if (prompt.trim()) {
      onGenerate(prompt.trim());
      setPrompt('');
      onClose();
    }
  };

  const handleExampleClick = (example: string) => {
    setPrompt(example);
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && prompt.trim()) {
      handleGenerate();
    }
  };

  // Always render but control visibility with CSS transform
  if (!isOpen) return null;

  return (
    <div className={`modal-overlay ${isOpen ? 'open' : ''}`}>
      <div className="component-modal">
        {/* Header */}
        <div className="modal-header">
          <h2>Edit Component 1</h2>
          <button className="close-btn" onClick={onClose}>
            <X size={20} />
          </button>
        </div>

        {/* Content */}
        <div className="modal-content">
          {/* Visual Elements */}
          <div className="visual-section">
            <div className="shapes-container">
              <div className="shape circle"></div>
              <div className="shape triangle"></div>
              <div className="shape square"></div>
              <div className="shape squiggle"></div>
            </div>
          </div>

          {/* Main Text */}
          <div className="text-section">
            <h1>What do you want to create?</h1>
            <p>Describe your idea or component, and MagicPath will bring it to life.</p>
          </div>

          {/* Upload Section */}
          <div className="upload-section">
            <Image size={16} />
            <span>Upload images to recreate designs</span>
          </div>

          {/* Example Prompts */}
          <div className="examples-section">
            {examplePrompts.map((example, index) => (
              <button 
                key={index}
                className="example-btn"
                onClick={() => handleExampleClick(example)}
              >
                {example}
              </button>
            ))}
          </div>
        </div>

        {/* Input Section */}
        <div className="input-section">
          <div className="input-container">
            <input
              type="text"
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="Ask MagicPath..."
              className="prompt-input"
            />
            <div className="input-controls">
              <div className="design-system-selector">
                <Image size={16} />
                <select 
                  value={designSystem}
                  onChange={(e) => setDesignSystem(e.target.value)}
                  className="design-system-dropdown"
                >
                  <option>No design system</option>
                  <option>Material UI</option>
                  <option>Tailwind CSS</option>
                  <option>Chakra UI</option>
                </select>
              </div>
              <button 
                className="generate-btn"
                onClick={handleGenerate}
                disabled={!prompt.trim()}
              >
                <Send size={16} />
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ComponentModal;
